"use client";

/**
 * Command palette (⌘K) — cold-start build on @gunjo/ui@0.0.1-alpha.2.
 *
 * Discovered entirely from the typed barrel (node_modules/@gunjo/ui/src/index.ts)
 * + the public docs API tables at https://www.gunjo.jp/docs/components/command-palette.
 *
 *  - `CommandPalette` (navigation) is the high-level, data-driven palette. It
 *    takes a `groups: CommandPaletteGroup[]` prop and renders the whole
 *    cmdk dialog (search input, grouped items w/ icons, shortcuts, empty state,
 *    arrow/Enter keyboard nav, Esc-to-close) for you. No need to hand-assemble
 *    Command/CommandInput/CommandItem.
 *  - It extends cmdk's `CommandDialog`, which extends Radix `DialogProps`, so it
 *    is controlled with `open` / `onOpenChange` — exactly as the docs API table
 *    lists. We own the ⌘K shortcut + button trigger and flip `open` ourselves.
 *  - `CommandPaletteAction` = { id, label, icon?, shortcut?, action() }. The
 *    `shortcut` string is shown as a right-aligned hint inside each item (via the
 *    internal CommandShortcut). We ALSO show a `Kbd` on the trigger card for the
 *    ⌘K hint itself.
 *  - Icons: the package bundles @tabler/icons-react. `Icon` wants an `icon`
 *    glyph + a `size` token ("xs"|"sm"|"md"|"lg"|"xl"). We pass `size="sm"`.
 *  - `useToast()` must live inside `<ToastProvider>`, so the interactive surface
 *    is split into <CommandDemo/> wrapped by <ToastProvider> at the page root.
 *    ToastType is "info" | "success" | "error".
 *
 *  No provider was required for the palette itself (it self-portals). The only
 *  provider is ToastProvider, and that's our choice for the feedback UX — the
 *  palette would work without it. No SSR/prerender crash occurred: the file is a
 *  client component ("use client") and CommandPalette guards its own portal.
 */

import * as React from "react";
import {
  Button,
  CommandPalette,
  type CommandPaletteGroup,
  Icon,
  Kbd,
  ToastProvider,
  useToast,
} from "@gunjo/ui";
import {
  IconLayoutDashboard,
  IconUser,
  IconSettings,
  IconBell,
  IconFileText,
  IconPlus,
  IconMoon,
  IconSun,
  IconLogout,
  IconSearch,
} from "@tabler/icons-react";

function CommandDemo() {
  const { showToast } = useToast();
  const [open, setOpen] = React.useState(false);
  const [lastAction, setLastAction] = React.useState<string | null>(null);
  const [theme, setTheme] = React.useState<"light" | "dark">("light");

  // ⌘K / Ctrl+K toggles the palette. (Mobile has no ⌘K, so the button below
  // is the equivalent trigger — matching the package's own command-palette-qa.)
  React.useEffect(() => {
    const onKeyDown = (e: KeyboardEvent) => {
      if (e.key.toLowerCase() === "k" && (e.metaKey || e.ctrlKey)) {
        e.preventDefault();
        setOpen((prev) => !prev);
      }
    };
    document.addEventListener("keydown", onKeyDown);
    return () => document.removeEventListener("keydown", onKeyDown);
  }, []);

  // Helper: a selected command closes the palette, records state, fires a toast.
  const run = React.useCallback(
    (
      label: string,
      message: string,
      type: "info" | "success" | "error" = "info",
      after?: () => void,
    ) => {
      setLastAction(label);
      setOpen(false);
      after?.();
      showToast(message, type);
    },
    [showToast],
  );

  const groups: CommandPaletteGroup[] = React.useMemo(
    () => [
      {
        heading: "ナビゲーション",
        items: [
          {
            id: "nav-dashboard",
            label: "ダッシュボードへ移動",
            icon: <Icon icon={IconLayoutDashboard} size="sm" />,
            shortcut: "G D",
            action: () => run("ダッシュボードへ移動", "ダッシュボードに移動しました", "info"),
          },
          {
            id: "nav-profile",
            label: "プロフィールを開く",
            icon: <Icon icon={IconUser} size="sm" />,
            shortcut: "G P",
            action: () => run("プロフィールを開く", "プロフィールを開きました", "info"),
          },
          {
            id: "nav-docs",
            label: "ドキュメントを閲覧",
            icon: <Icon icon={IconFileText} size="sm" />,
            shortcut: "G F",
            action: () => run("ドキュメントを閲覧", "ドキュメントを開きました", "info"),
          },
        ],
      },
      {
        heading: "アクション",
        items: [
          {
            id: "action-new",
            label: "新しいドキュメントを作成",
            icon: <Icon icon={IconPlus} size="sm" />,
            shortcut: "⌘ N",
            action: () =>
              run("新しいドキュメントを作成", "新しいドキュメントを作成しました", "success"),
          },
          {
            id: "action-search",
            label: "すべてを検索",
            icon: <Icon icon={IconSearch} size="sm" />,
            shortcut: "⌘ /",
            action: () => run("すべてを検索", "検索を開始しました", "info"),
          },
          {
            id: "action-notify",
            label: "通知を表示",
            icon: <Icon icon={IconBell} size="sm" />,
            shortcut: "⌘ B",
            action: () =>
              run("通知を表示", "新しい通知はありません", "info"),
          },
        ],
      },
      {
        heading: "設定",
        items: [
          {
            id: "settings-theme",
            label: "テーマを切り替え",
            icon: (
              <Icon icon={theme === "light" ? IconMoon : IconSun} size="sm" />
            ),
            shortcut: "⌘ ⇧ L",
            action: () =>
              run(
                "テーマを切り替え",
                `${theme === "light" ? "ダーク" : "ライト"}テーマに切り替えました`,
                "success",
                () => setTheme((t) => (t === "light" ? "dark" : "light")),
              ),
          },
          {
            id: "settings-prefs",
            label: "設定を開く",
            icon: <Icon icon={IconSettings} size="sm" />,
            shortcut: "⌘ ,",
            action: () => run("設定を開く", "設定を開きました", "info"),
          },
          {
            id: "settings-logout",
            label: "ログアウト",
            icon: <Icon icon={IconLogout} size="sm" />,
            action: () => run("ログアウト", "ログアウトしました", "error"),
          },
        ],
      },
    ],
    [run, theme],
  );

  return (
    <main className="mx-auto flex min-h-screen w-full max-w-2xl flex-col items-center justify-center gap-8 px-6 py-24">
      <div className="flex flex-col items-center gap-3 text-center">
        <h1 className="text-3xl font-semibold tracking-tight text-foreground">
          コマンドパレット
        </h1>
        <p className="max-w-md text-sm text-muted-foreground">
          このページ上のどこでも{" "}
          <Kbd>
            <span className="text-[11px]">⌘</span>K
          </Kbd>{" "}
          （または{" "}
          <Kbd>
            <span className="text-[11px]">Ctrl</span>K
          </Kbd>
          ）を押すとパレットが開きます。下のボタンからも開けます。
          入力で絞り込み、↑/↓ で移動、Enter でコマンドを実行します。
        </p>
      </div>

      <Button onClick={() => setOpen(true)} className="gap-2">
        <Icon icon={IconSearch} size="sm" />
        コマンドパレットを開く
        <Kbd className="ml-1 border-primary-strong-foreground/30 bg-transparent text-primary-strong-foreground/90">
          ⌘K
        </Kbd>
      </Button>

      <div
        aria-live="polite"
        className="flex min-h-[2.5rem] items-center justify-center rounded-lg border border-border bg-muted/40 px-4 py-2 text-sm text-muted-foreground"
      >
        {lastAction ? (
          <span>
            最後のコマンド:{" "}
            <span className="font-medium text-foreground">{lastAction}</span>
            {"  ·  "}
            <span className="text-foreground">{theme === "light" ? "ライト" : "ダーク"}</span>テーマ
          </span>
        ) : (
          <span>まだコマンドは実行されていません。</span>
        )}
      </div>

      <CommandPalette
        open={open}
        onOpenChange={setOpen}
        groups={groups}
        placeholder="コマンドを入力するか検索…"
        emptyMessage="該当するコマンドがありません。"
      />
    </main>
  );
}

export default function CommandPage() {
  return (
    <ToastProvider>
      <CommandDemo />
    </ToastProvider>
  );
}
